// Consolidate 3 RAG outputs + original payload into Writer input
// v6.0: Enhanced with site context and structured RAG section headers
const ragItems = $input.all();
const trigger = $('Execute Workflow Trigger').first().json;

// Extract agent outputs (each returns JSON in .output or .text)
const coreData = ragItems[0]?.json?.output || ragItems[0]?.json?.text || '{"hechos_clave_extraidos":[]}';
const hermanos = ragItems[1]?.json?.output || ragItems[1]?.json?.text || '{"articulos_hermanos_relevantes":[]}';
const claims   = ragItems[2]?.json?.output || ragItems[2]?.json?.text || '{"claims_antitesis":[],"metadata_busqueda":{}}';

// Build comprehensive writer input with structured context
const writerInput = `
═══════════════════════════════════════════════
TEMA SEMANAL: ${trigger.tema_semanal}
ÁNGULO DE ENFOQUE: ${trigger.angulo_enfoque}
IDIOMA DEL ARTÍCULO: ${trigger.idioma === 'es' ? 'Español neutro' : 'English'}
SITIO: ${trigger.publisher_name} (${trigger.wp_url})
AUTOR: ${trigger.author_name || 'N/A'}
FECHA PUBLICACIÓN: ${trigger.wp_scheduled_date || 'N/A'}
═══════════════════════════════════════════════

<rag_context>

<section id="core_data" source="everest-core-002">
${coreData}
</section>

<section id="hermanos" source="everest-brothers-01">
${hermanos}
</section>

<section id="antitesis" source="antitesis-research">
${claims}
</section>

</rag_context>

═══════════════════════════════════════════════
INSTRUCCIÓN FINAL:
Usando TODA la información dentro de <rag_context> como tu contexto verificado, genera el artículo completo en formato JSON según las instrucciones de tu System Prompt.

REQUISITOS MÍNIMOS DE INTEGRACIÓN:
- Mínimo 3 interlinks de la sección hermanos (usar URLs exactas del contexto).
- Mínimo 1 bloque de análisis de riesgo usando datos de la sección antitesis.
- Cada dato estadístico DEBE tener respaldo en core_data o antitesis.
- Si un dato no tiene respaldo en el contexto RAG, marcarlo como [DATO NO DISPONIBLE EN CONTEXTO].
═══════════════════════════════════════════════
`.trim();

return [{
  json: {
    writer_input: writerInput,
    rag_cache: {
      core_data: coreData,
      hermanos: hermanos,
      claims: claims
    },
    ...trigger
  }
}];

// Parse Director de Arte output and prepare prompt for native Gemini Image node
const directorOutput = $json.output || $json.text || '{}';
const prev = $('Set - Extract Output & Creds').first().json;

let parsed;
try {
  // Try to parse as JSON (Director should return JSON)
  const cleanText = directorOutput
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  parsed = JSON.parse(cleanText);
} catch (e) {
  // Fallback: use the raw text as the prompt
  parsed = {
    final_prompt: directorOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim()
  };
}

// Build the final prompt — prioritize final_prompt, then compose from parts
const finalPrompt = parsed.final_prompt 
  || [
    parsed.scene_description || '',
    parsed.style_keywords || '',
    parsed.aspect_ratio || 'aspect ratio 16:9'
  ].filter(Boolean).join(', ');

if (!finalPrompt || finalPrompt.length < 10) {
  throw new Error('Director de Arte no generó un prompt válido. Output recibido: ' + directorOutput.substring(0, 200));
}

// Output: the Gemini native node reads $json.image_prompt
return [{
  json: {
    image_prompt: finalPrompt,
    // Pass through all article + WP data for downstream nodes
    ...prev
  }
}];

// ═══ Create WordPress Post (Two-Step: Draft → Publish) ═══
// Step 1: Create as DRAFT (wp_insert_post fires)
// Step 2: Update to PUBLISH (edit_post + transition_post_status fires → Breeze purges cache)

const uploadResult = $json;
const creds = $('Execute Workflow Trigger').first().json;
const articleData = $('Set - Extract Output & Creds').first().json;

const wpUrl = creds.wp_url.replace(/\/$/, '');
const authHeader = 'Basic ' + Buffer.from(creds.wp_user + ':' + creds.wp_app_password).toString('base64');

// --- Parse tags ---
let tags = articleData.tags_sugeridos_array;
if (typeof tags === 'string') {
  try { tags = JSON.parse(tags); } catch(e) { tags = []; }
}

// --- Content with JSON-LD intact ---
const cleanContent = (articleData.cuerpo_articulo_html || '').trim();

// ═══ STEP 1: Create as DRAFT ═══
const draftBody = {
  title: articleData.titulo_generado,
  content: cleanContent,
  slug: articleData.slug_generado,
  status: 'draft',
  featured_media: uploadResult.media_id || 0
};

let postId;
try {
  const draftResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `${wpUrl}/wp-json/wp/v2/posts`,
    headers: {
      'Content-Type': 'application/json',
      'Authorization': authHeader
    },
    body: draftBody,
    returnFullResponse: false
  });

  postId = draftResponse.id || null;
  if (!postId) {
    throw new Error('WP draft response has no ID: ' + JSON.stringify(draftResponse).substring(0, 300));
  }
} catch (error) {
  throw new Error(`WordPress DRAFT creation failed for ${creds.site_id}: ${error.message}`);
}

// ═══ STEP 2: Update to PUBLISH ═══
// This PUT triggers edit_post + post_updated + transition_post_status('draft' → 'publish')
// which is what Breeze hooks into for automatic cache purge
let postUrl;
try {
  const publishResponse = await this.helpers.httpRequest({
    method: 'PUT',
    url: `${wpUrl}/wp-json/wp/v2/posts/${postId}`,
    headers: {
      'Content-Type': 'application/json',
      'Authorization': authHeader
    },
    body: {
      status: 'publish'
    },
    returnFullResponse: false
  });

  postUrl = publishResponse.link || '';

} catch (error) {
  throw new Error(`WordPress PUBLISH update failed for ${creds.site_id} (post ${postId}): ${error.message}`);
}

return [{
  json: {
    post_id: postId,
    post_url: postUrl,
    media_id: uploadResult.media_id,
    titulo_seo: articleData.titulo_seo_generado,
    meta_descripcion: articleData.meta_descripcion_generada,
    tags_array: tags,
    preguntas_frecuentes: articleData.preguntas_frecuentes_array,
    site_id: creds.site_id
  }
}];

// ═══ Prepare Image Binary for WP Upload ═══
// v6 FINAL — Registers binary via prepareBinaryData (efficient streaming, no CPU spike)
// Pre-computes WP auth header (Buffer not available in HTTP Request node expressions)
// Actual upload happens in the NEXT node (native HTTP Request)

const items = $input.all();
const item  = items[0];

// All data comes from Set - Extract Output & Creds
const prev = $('Set - Extract Output & Creds').first().json;
const slug    = prev.slug_generado || 'featured';
const siteId  = prev.site_id || 'everest';
const filename = `${siteId}-${slug}-${Date.now()}.png`;

// ── 1. Get the raw image buffer ──
let imageBuffer;
try {
  imageBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
} catch (bufErr) {
  if (item.binary && item.binary.data && item.binary.data.data) {
    imageBuffer = Buffer.from(item.binary.data.data, 'base64');
  } else {
    throw new Error('No binary data available: ' + bufErr.message);
  }
}

if (!imageBuffer || imageBuffer.length === 0) {
  throw new Error('Image buffer is empty — Gemini may not have returned an image.');
}

// ── 2. Register in n8n's binary system (efficient streaming, no CPU spike) ──
const binaryData = await this.helpers.prepareBinaryData(
  imageBuffer,
  filename,
  'image/png'
);

// ── 3. Pre-compute WP auth header (Buffer is NOT available in HTTP Request node expressions) ──
const wpAuthHeader = 'Basic ' + Buffer.from(
  String(prev.wp_user).trim() + ':' + String(prev.wp_app_password).trim()
).toString('base64');

// ── 4. Pass EVERYTHING forward for downstream nodes ──
return [{
  json: {
    // Upload metadata
    filename: filename,
    buffer_size_kb: Math.round(imageBuffer.length / 1024),

    // WP credentials (raw + pre-computed auth)
    wp_url: prev.wp_url,
    wp_user: prev.wp_user,
    wp_app_password: prev.wp_app_password,
    wp_auth_header: wpAuthHeader,
    site_id: prev.site_id,

    // Article data passthrough for Create Post + RankMath downstream
    titulo_generado: prev.titulo_generado,
    slug_generado: prev.slug_generado,
    cuerpo_articulo_html: prev.cuerpo_articulo_html,
    titulo_seo_generado: prev.titulo_seo_generado,
    meta_descripcion_generada: prev.meta_descripcion_generada,
    tags_sugeridos_array: prev.tags_sugeridos_array,
    preguntas_frecuentes_array: prev.preguntas_frecuentes_array,
    wp_scheduled_date: prev.wp_scheduled_date,
    author_name: prev.author_name
  },
  binary: {
    data: binaryData
  }
}];

// ═══ Bridge: Normalize WP Upload Response ═══
// WordPress returns { id, source_url, ... } from the HTTP Request node
// Downstream expects { media_id, media_url, filename, buffer_size_kb }

const wpResponse = $json;

return [{
  json: {
    media_id: wpResponse.id || null,
    media_url: wpResponse.source_url || '',
    filename: wpResponse.title?.rendered || wpResponse.slug || '',
    buffer_size_kb: 0
  }
}];

// ============================================================
// Code - Parse Writer Output v3.1
// 1. Parses JSON from Agent - Escritor (with 2-level recovery)
// 2. Builds SEO JSON-LD (Article + FAQPage + ClaimReview)
// 3. Appends <script type="application/ld+json"> to HTML body
// ============================================================

const items = $input.all();
const item = items[0];
const raw = item.json.output || item.json.text || '';

if (!raw || typeof raw !== 'string') {
  throw new Error(
    'Writer output is empty or not a string. ' +
    'Type: ' + typeof raw + ' | Keys: ' + Object.keys(item.json).join(', ')
  );
}

// ═══════════════════════════════════════════
// PHASE 1: Parse Writer JSON
// ═══════════════════════════════════════════

let cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

const firstBrace = cleaned.indexOf('{');
const lastBrace  = cleaned.lastIndexOf('}');

if (firstBrace === -1 || lastBrace === -1 || lastBrace <= firstBrace) {
  throw new Error(
    'Writer output does not contain a valid JSON object. ' +
    'First 500 chars: ' + raw.substring(0, 500)
  );
}

cleaned = cleaned.substring(firstBrace, lastBrace + 1);

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // ═══ Recovery Level 1: Fix unescaped newlines/tabs inside JSON string values ═══
  // Walk character-by-character: when inside a quoted string, replace literal
  // newlines/tabs with their escaped equivalents.
  // Handles Hershey's-style apostrophes, long HTML with line breaks, etc.
  try {
    let inString = false;
    let escaped = false;
    let fixed = '';
    for (let i = 0; i < cleaned.length; i++) {
      const ch = cleaned[i];
      if (escaped) {
        fixed += ch;
        escaped = false;
        continue;
      }
      if (ch === '\\') {
        fixed += ch;
        escaped = true;
        continue;
      }
      if (ch === '"') {
        inString = !inString;
        fixed += ch;
        continue;
      }
      if (inString) {
        if (ch === '\n') { fixed += '\\n'; continue; }
        if (ch === '\r') { fixed += '\\r'; continue; }
        if (ch === '\t') { fixed += '\\t'; continue; }
      }
      fixed += ch;
    }
    parsed = JSON.parse(fixed);
  } catch (e2) {
    // ═══ Recovery Level 2: Truncation repair ═══
    // If Gemini output was cut mid-string, try to close the JSON gracefully
    try {
      let truncated = cleaned;
      // Close any open string
      const quoteCount = (truncated.match(/(?<!\\)"/g) || []).length;
      if (quoteCount % 2 !== 0) truncated += '"';
      // Close open braces/brackets
      const openBraces = (truncated.match(/{/g) || []).length;
      const closeBraces = (truncated.match(/}/g) || []).length;
      const openBrackets = (truncated.match(/\[/g) || []).length;
      const closeBrackets = (truncated.match(/\]/g) || []).length;
      for (let b = 0; b < openBrackets - closeBrackets; b++) truncated += ']';
      for (let b = 0; b < openBraces - closeBraces; b++) truncated += '}';
      parsed = JSON.parse(truncated);
    } catch (e3) {
      throw new Error(
        'JSON parse failed after 2 recovery attempts: ' + e.message +
        ' | Near position: ' + (e.message.match(/position (\d+)/) || ['','?'])[1] +
        ' | First 300 chars: ' + cleaned.substring(0, 300)
      );
    }
  }
}

const required = [
  'titulo_generado',
  'cuerpo_articulo_html',
  'slug_generado',
  'titulo_seo_generado',
  'meta_descripcion_generada',
  'tags_sugeridos_array',
  'preguntas_frecuentes_array'
];

const missing = required.filter(f => !parsed[f]);
if (missing.length > 0) {
  throw new Error('Writer output missing required fields: ' + missing.join(', '));
}

// ═══════════════════════════════════════════
// PHASE 2: Build JSON-LD Schemas
// ═══════════════════════════════════════════

const trigger = $('Execute Workflow Trigger').first().json;

// --- Helper: safe array parse ---
function safeArray(val) {
  if (Array.isArray(val)) return val;
  if (typeof val === 'string') {
    try { return JSON.parse(val); } catch(e) { return []; }
  }
  return [];
}

// --- Helper: extract date portion from ISO string ---
function extractDate(dateStr) {
  if (!dateStr) return new Date().toISOString().split('T')[0];
  return String(dateStr).split('T')[0];
}

const pubDate = extractDate(trigger.wp_scheduled_date);
const tags = safeArray(parsed.tags_sugeridos_array);
const faq  = safeArray(parsed.preguntas_frecuentes_array);

// ── 2a. Article Schema ──
const articleSchema = {
  "@context": "https://schema.org",
  "@type": "Article",
  "headline": parsed.titulo_generado,
  "description": parsed.meta_descripcion_generada,
  "author": {
    "@type": "Person",
    "name": trigger.author_name || 'Staff Writer'
  },
  "publisher": {
    "@type": "Organization",
    "name": trigger.publisher_name || ''
  },
  "datePublished": pubDate,
  "dateModified": pubDate
};

// Enrich author if we have jobTitle and bio
if (trigger.author_title) {
  articleSchema.author.jobTitle = trigger.author_title;
}
if (trigger.author_bio) {
  articleSchema.author.description = trigger.author_bio;
}

// Enrich author.alumniOf if available (JSON array string from Sheets)
if (trigger.author_alumni_json) {
  try {
    const alumni = JSON.parse(trigger.author_alumni_json);
    if (Array.isArray(alumni) && alumni.length > 0) {
      articleSchema.author.alumniOf = alumni.map(org => ({
        "@type": "Organization",
        "name": typeof org === 'string' ? org : org.name
      }));
    }
  } catch(e) { /* skip malformed alumni */ }
}

// Enrich publisher.logo if available
if (trigger.publisher_logo_url) {
  articleSchema.publisher.logo = {
    "@type": "ImageObject",
    "url": trigger.publisher_logo_url
  };
}

// Keywords as DefinedTerm (first 2 = primary, next 2 = contextual, rest = semantic)
if (tags.length > 0) {
  articleSchema.keywords = tags.map((tag, i) => ({
    "@type": "DefinedTerm",
    "name": typeof tag === 'string' ? tag : (tag.name || tag),
    "category": i < 2 ? "primary" : (i < 4 ? "contextual" : "semantic")
  }));
}

// ── 2b. FAQPage Schema ──
let faqSchema = null;
if (faq.length > 0) {
  faqSchema = {
    "@context": "https://schema.org",
    "@type": "FAQPage",
    "mainEntity": faq.map(item => ({
      "@type": "Question",
      "name": item.pregunta || item.question || item.q || item.name || '',
      "acceptedAnswer": {
        "@type": "Answer",
        "text": item.respuesta || item.answer || item.a || item.text || ''
      }
    })).filter(q => q.name && q.acceptedAnswer.text)
  };
  // Only include if we have valid Q&A pairs
  if (faqSchema.mainEntity.length === 0) faqSchema = null;
}

// ── 2c. ClaimReview Schema (from antitesis RAG data) ──
let claimSchema = null;
try {
  const ragCache = $('Code - Build Writer Input').first()?.json?.rag_cache;
  if (ragCache && ragCache.claims) {
    let claimsData = ragCache.claims;
    if (typeof claimsData === 'string') {
      claimsData = JSON.parse(claimsData);
    }

    // Extract the strongest claim (highest confidence score)
    const claimsArray = claimsData.claims_antitesis || claimsData.claims || [];
    if (Array.isArray(claimsArray) && claimsArray.length > 0) {
      // Pick the claim with highest score, or first one
      const topClaim = claimsArray.reduce((best, curr) => {
        const currScore = curr.confidence_score || curr.score || curr.relevance || 0;
        const bestScore = best.confidence_score || best.score || best.relevance || 0;
        return currScore > bestScore ? curr : best;
      }, claimsArray[0]);

      const claimText = topClaim.claim || topClaim.afirmacion || topClaim.text || '';
      const sourceOrg = topClaim.source || topClaim.fuente || topClaim.organization || '';
      const score = topClaim.confidence_score || topClaim.score || topClaim.relevance || 0;

      if (claimText) {
        // Map confidence score (0-1 or 0-100) to rating (1-5)
        const normalizedScore = score > 1 ? score / 100 : score;
        const ratingValue = Math.max(1, Math.min(5, Math.round(normalizedScore * 5)));

        claimSchema = {
          "@context": "https://schema.org",
          "@type": "ClaimReview",
          "claimReviewed": claimText,
          "reviewRating": {
            "@type": "Rating",
            "ratingValue": String(ratingValue),
            "bestRating": "5",
            "ratingExplanation": topClaim.analysis || topClaim.analisis ||
              topClaim.counter_argument || topClaim.contraargumento || ''
          },
          "itemReviewed": {
            "@type": "Claim",
            "author": {
              "@type": "Organization",
              "name": typeof sourceOrg === 'string' ? sourceOrg : (sourceOrg.name || 'Source')
            }
          },
          "author": {
            "@type": "Person",
            "name": trigger.author_name || 'Staff Writer'
          }
        };

        // Clean: remove ratingExplanation if empty
        if (!claimSchema.reviewRating.ratingExplanation) {
          delete claimSchema.reviewRating.ratingExplanation;
        }
      }
    }
  }
} catch(e) {
  // ClaimReview is optional — if RAG cache is unavailable, skip silently
  claimSchema = null;
}

// ── 2d. Assemble JSON-LD array ──
const jsonLdArray = [articleSchema];
if (faqSchema)   jsonLdArray.push(faqSchema);
if (claimSchema) jsonLdArray.push(claimSchema);

const jsonLdScript = '\n<script type="application/ld+json">\n' +
  JSON.stringify(jsonLdArray, null, 2) +
  '\n</script>\n';

// ═══════════════════════════════════════════
// PHASE 3: Append JSON-LD to HTML body
// ═══════════════════════════════════════════

// First, strip any existing JSON-LD the Writer may have generated
// (avoid duplicates if the LLM also tried to include schema)
let htmlBody = (parsed.cuerpo_articulo_html || '')
  .replace(/<script\b[^>]*type=['"]?application\/ld\+json['"]?[^>]*>[\s\S]*?<\/script>/gi, '')
  .trim();

// AGREGAR DESPUÉS — strip de JSON-LD raw sin wrapper:
// Elimina bloques que empiecen con [{ "@context": "https://schema.org"
// o con { "@context": "https://schema.org" al final del HTML
htmlBody = htmlBody
  .replace(/\[\s*\{\s*"@context"\s*:\s*"https:\/\/schema\.org"[\s\S]*?\}\s*\]/gi, '')
  .replace(/\{\s*"@context"\s*:\s*"https:\/\/schema\.org"[\s\S]*?\}\s*$/gi, '')
  .trim();

// Append our programmatically-built JSON-LD
htmlBody = htmlBody + jsonLdScript;

// ═══════════════════════════════════════════
// PHASE 4: Return merged output
// ═══════════════════════════════════════════

return [{
  json: {
    ...parsed,
    cuerpo_articulo_html: htmlBody,  // Overwrite with JSON-LD appended
    ...trigger
  }
}];
